const file = $.steps.fetchDocument.response || {};
const name = file.name || file.title || 'Document';
const content = file.content || file.body || '';
const contentStr = typeof content === 'string' ? content : JSON.stringify(content);
return { name, content: contentStr.slice(0, 8000), fullLength: contentStr.length };

const doc = $.steps.extractContent.output;
const prompt = $.input.assistantRole + '

DOCUMENT: ' + doc.name + '

CONTENT:
' + doc.content + '

USER QUESTION: ' + $.input.question + '

Provide a clear, specific answer based on the document. If quoting from the document, use quotation marks. Return ONLY valid JSON:
{
  "answer": "your detailed answer",
  "confidence": "high/medium/low",
  "relevantQuotes": ["quote from document if applicable"],
  "followUpQuestions": ["suggested follow-up question 1"]
}';
return { prompt };

let raw = $.steps.aiAnswer.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { answer: raw, confidence: 'medium', relevantQuotes: [], followUpQuestions: [] }; }

const ai = $.steps.parseAI.output;
const doc = $.steps.extractContent.output;
const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Knowledge Assistant Answer', emoji: true } });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Document:*\n' + doc.name },
  { type: 'mrkdwn', text: '*Confidence:*\n' + (ai.confidence || 'N/A') }
] });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Q:* ' + $.input.question } });
blocks.push({ type: 'divider' });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*A:* ' + (ai.answer || 'No answer generated').slice(0, 1800) } });
if (ai.relevantQuotes && ai.relevantQuotes.length > 0) {
  let qText = '*Relevant Quotes:*\n';
  ai.relevantQuotes.forEach(q => { qText += '> ' + q + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: qText.slice(0, 1800) } });
}
if (ai.followUpQuestions && ai.followUpQuestions.length > 0) {
  blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Follow-up: ' + ai.followUpQuestions.join(' | ') }] });
}
const fallback = 'Q: ' + $.input.question + ' A: ' + (ai.answer || '').slice(0, 200);
return { blocks, fallback };
